function solve(points) {
    const n = points.length;
    if (n < 4) return 0;

    let count = 0;
    const lines = new Map();

    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j < n; j++) {
            const x1 = points[i][0], y1 = points[i][1];
            const x2 = points[j][0], y2 = points[j][1];
            let key;
            if (x1 === x2) {
                key = `inf_${x1}`;
            } else {
                const slope = (y2 - y1) / (x2 - x1);
                const intercept = y1 - slope * x1;
                key = `${slope}_${intercept}`;
            }
            if (!lines.has(key)) {
                lines.set(key, []);
            }
            lines.get(key).push([i, j]);
        }
    }

    for (const [key, linePairs] of lines) {
        if (linePairs.length < 2) continue;
        const m = linePairs.length;
        for (let i = 0; i < m; i++) {
            for (let j = i + 1; j < m; j++) {
                const [a, b] = linePairs[i];
                const [c, d] = linePairs[j];
                const set = new Set([a, b, c, d]);
                if (set.size === 4) {
                    count++;
                }
            }
        }
    }

    return count / 3; // Each trapezoid is counted 3 times (once for each pair of parallel sides)
}

