                key = to_string(dy) + "_" + to_string(dx) + "_" + to_string(intercept_num) + "_" + to_string(intercept_den);
            }
            lines[key].emplace_back(i, j);
        }
    }

    long long count = 0;
    for (const auto& entry : lines) {
        const auto& line_pairs = entry.second;
        int m = line_pairs.size();
        if (m < 2) continue;
